<script setup lang="ts">import{ref,onMounted}from'vue';import{RouterLink}from'vue-router';import{fetchReservations}from'@/services/reservation';import type{Reservation}from'@/types/reservation';const list=ref<Reservation[]>([]),errorMessage=ref('');onMounted(async()=>{try{list.value=(await fetchReservations()).list}catch(e){errorMessage.value=e instanceof Error?e.message:'预订加载失败'}})</script><template><section class="page-section"><div class="page-header"><div><p class="eyebrow">我的预订</p><h1>待确认、已确认、取消和改期都在一条时间线上。</h1></div></div><p v-if="errorMessage" class="feedback is-error">{{errorMessage}}</p><div class="rank-list"><RouterLink v-for="r in list" :key="r.id" :to="`/user/reservations/${r.id}`" class="content-card rank-item"><img :src="r.shop.coverImage" :alt="r.shop.name"><div class="rank-item__body"><h2>{{r.shop.name}}</h2><p>{{r.reserveTime}} · {{r.peopleCount}} 人</p><span class="status-pill">{{r.statusText}}</span></div></RouterLink></div></section></template>
